import React, { useState, useRef, useCallback } from 'react';
import UploadZone from '../components/UploadZone';
import ImagePreviewGrid from '../components/ImagePreviewGrid';
import SubmitPanel from '../components/SubmitPanel';
import './UploadPage.css';

export default function UploadPage() {
  const [files, setFiles] = useState([]);      // Array of { id, file, preview, status }
  const [examName, setExamName] = useState('');
  const [subject, setSubject] = useState('');
  const [submitting, setSubmitting] = useState(false);
  const [submitted, setSubmitted] = useState(false);

  // Add new files (deduplicate by name+size)
  const addFiles = useCallback((incoming) => {
    const newEntries = incoming
      .filter(f => f.type.startsWith('image/'))
      .map(f => ({
        id: `${f.name}-${f.size}-${Date.now()}-${Math.random()}`,
        file: f,
        preview: URL.createObjectURL(f),
        status: 'ready',   // ready | uploading | done | error
      }))
      .filter(entry => !files.some(ex => ex.file.name === entry.file.name && ex.file.size === entry.file.size));

    if (newEntries.length > 0) {
      setFiles(prev => [...prev, ...newEntries]);
      setSubmitted(false);
    }
  }, [files]);

  const removeFile = useCallback((id) => {
    setFiles(prev => {
      const target = prev.find(f => f.id === id);
      if (target) URL.revokeObjectURL(target.preview);
      return prev.filter(f => f.id !== id);
    });
  }, []);

  const clearAll = useCallback(() => {
    files.forEach(f => URL.revokeObjectURL(f.preview));
    setFiles([]);
    setSubmitted(false);
  }, [files]);

  // Simulate upload — replace this with your real API call later
  const handleSubmit = async () => {
    if (!files.length || submitting) return;
    setSubmitting(true);

    // Mark all as uploading
    setFiles(prev => prev.map(f => ({ ...f, status: 'uploading' })));

    // Simulate sequential processing with a delay
    for (let i = 0; i < files.length; i++) {
      await new Promise(res => setTimeout(res, 600 + Math.random() * 400));
      setFiles(prev => prev.map((f, idx) =>
        idx === i ? { ...f, status: 'done' } : f
      ));
    }

    setSubmitting(false);
    setSubmitted(true);

    /* ─── REAL API CALL (uncomment when backend is ready) ──────────────────
    const formData = new FormData();
    formData.append('exam_name', examName);
    formData.append('subject', subject);
    files.forEach(entry => formData.append('papers', entry.file));

    try {
      const res = await fetch('http://localhost:8000/api/upload', {
        method: 'POST',
        body: formData,
      });
      const data = await res.json();
      console.log('Upload response:', data);
    } catch (err) {
      console.error('Upload failed:', err);
    }
    ──────────────────────────────────────────────────────────────────────── */
  };

  return (
    <div className="upload-page">
      {/* Page header */}
      <div className="upload-header fade-up">
        <div className="upload-header-text">
          <h1>Upload Answer Sheets</h1>
          <p>Drag and drop scanned exam papers. Supports JPG, PNG, and WEBP.</p>
        </div>
        <div className="upload-header-meta">
          <span className="meta-chip">
            <svg width="14" height="14" viewBox="0 0 14 14" fill="none" aria-hidden="true">
              <path d="M7 1v6M7 10v.5" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round"/>
              <circle cx="7" cy="7" r="6" stroke="currentColor" strokeWidth="1"/>
            </svg>
            AI-powered grading
          </span>
        </div>
      </div>

      {/* Exam details fields */}
      <div className="exam-meta-row fade-up fade-up-delay-1">
        <div className="field-group">
          <label htmlFor="exam-name" className="field-label">Exam / Assessment Name</label>
          <input
            id="exam-name"
            type="text"
            className="field-input"
            placeholder="e.g. Midterm Exam — Chapter 4"
            value={examName}
            onChange={e => setExamName(e.target.value)}
          />
        </div>
        <div className="field-group">
          <label htmlFor="subject" className="field-label">Subject</label>
          <input
            id="subject"
            type="text"
            className="field-input"
            placeholder="e.g. Introduction to Programming"
            value={subject}
            onChange={e => setSubject(e.target.value)}
          />
        </div>
      </div>

      {/* Upload zone */}
      <div className="fade-up fade-up-delay-2">
        <UploadZone onFilesSelected={addFiles} hasFiles={files.length > 0} />
      </div>

      {/* Preview grid */}
      {files.length > 0 && (
        <div className="fade-up">
          <ImagePreviewGrid files={files} onRemove={removeFile} />
        </div>
      )}

      {/* Submit panel */}
      <div className="fade-up fade-up-delay-3">
        <SubmitPanel
          fileCount={files.length}
          submitting={submitting}
          submitted={submitted}
          examName={examName}
          onSubmit={handleSubmit}
          onClear={clearAll}
        />
      </div>
    </div>
  );
}
